{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-citation-ordering-diagnostics-before-artifacts-before-snapshot-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "locale": "zh-CN",
  "status": "partial",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "基于当前选中的流股“Cold Feed” (feed-15) 和单元“Guard Heater” (heater-5) 的诊断，生成两项最小候选提案，分别补全缺失的流量规格与出口温度目标，不改变拓扑或求解策略。",
      "issues": [
        "流股 feed-15 缺少流量规格，直接影响物料平衡与求解有效性 (STREAM_SPEC_MISSING)",
        "加热器 heater-5 在出口温度控制模式下缺少出口温度目标，导致控制设定不完整 (UNIT_PARAMETER_INCOMPLETE)"
      ],
      "proposed_actions": [
        {
          "title": "为 Cold Feed 添加流量规格占位",
          "target": "feed-15",
          "rationale": "STREAM_SPEC_MISSING 诊断指出该流股无流量规格，求解器无法建立物料平衡方程。当前 flowsheet_document 中 flowdoc-stream-1 未记录任何流量参数，因此建议插入保护性占位。",
          "patch": {
            "spec_placeholders": {
              "flow_rate": {
                "value_unit": "kg/s",
                "note": "待补充实际流量值"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "confidence": 0.9,
          "citations": [
            {
              "source_type": "diagnostic",
              "source_id": "diag-1"
            },
            {
              "source_type": "artifact",
              "source_id": "flowdoc-stream-1"
            },
            {
              "source_type": "snapshot",
              "source_id": "snapshot-1"
            }
          ]
        },
        {
          "title": "为 Guard Heater 添加出口温度目标",
          "target": "heater-5",
          "rationale": "UNIT_PARAMETER_INCOMPLETE 诊断指出该加热器控制模式为 outlet_temperature 但缺少目标值，导致控制方程无法闭合。flowsheet_document 中 flowdoc-unit-1 的 config 仅设置了 control_mode，未提供目标温度。",
          "patch": {
            "parameter_placeholders": {
              "outlet_temperature_target": {
                "value_unit": "°C",
                "note": "待设定期望出口温度"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "confidence": 0.9,
          "citations": [
            {
              "source_type": "diagnostic",
              "source_id": "diag-2"
            },
            {
              "source_type": "artifact",
              "source_id": "flowdoc-unit-1"
            },
            {
              "source_type": "snapshot",
              "source_id": "snapshot-1"
            }
          ]
        }
      ]
    }
  ]
}
